import os
from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql, Error

app = Flask(__name__)

# Database connection details - use environment variables for production
DB_NAME = os.environ.get("DB_NAME", "your_database_name")
DB_USER = os.environ.get("DB_USER", "your_username")
DB_PASSWORD = os.environ.get("DB_PASSWORD", "your_password")
DB_HOST = os.environ.get("DB_HOST", "localhost")
DB_PORT = os.environ.get("DB_PORT", "5432")

def get_db_connection():
    """Establishes and returns a database connection."""
    try:
        conn = psycopg2.connect(
            dbname=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD,
            host=DB_HOST,
            port=DB_PORT
        )
        return conn
    except Error as e:
        print(f"Error connecting to the database: {e}")
        return None

@app.route('/query', methods=['POST'])
def dynamic_query():
    """
    Executes dynamic SQL queries based on JSON input.
    Expected JSON format:
    {
        "table": "your_table_name",
        "columns": ["col1", "col2"],
        "filters": [
            {"column": "col1", "operator": "=", "value": "some_value"},
            {"column": "col2", "operator": ">", "value": 100}
        ],
        "limit": 10,
        "offset": 0,
        "order_by": [{"column": "col1", "direction": "ASC"}]
    }
    """
    data = request.get_json()

    table_name = data.get('table')
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    limit = data.get('limit')
    offset = data.get('offset')
    order_by = data.get('order_by', [])

    if not table_name:
        return jsonify({"error": "Table name is required"}), 400

    conn = None
    try:
        conn = get_db_connection()
        if conn is None:
            return jsonify({"error": "Database connection failed"}), 500

        cur = conn.cursor()

        # Build SELECT part
        if columns == ['*']:
            select_cols = sql.SQL('*')
        else:
            # Validate column names to prevent SQL injection
            for col in columns:
                if not isinstance(col, str) or not col.isidentifier():
                    return jsonify({"error": f"Invalid column name: {col}"}), 400
            select_cols = sql.SQL(', ').join(map(sql.Identifier, columns))

        # Validate table name
        if not isinstance(table_name, str) or not table_name.isidentifier():
            return jsonify({"error": f"Invalid table name: {table_name}"}), 400

        query_parts = [
            sql.SQL("SELECT {} FROM {}").format(
                select_cols,
                sql.Identifier(table_name)
            )
        ]
        params = []

        # Build WHERE part
        if filters:
            where_clauses = []
            for f in filters:
                col = f.get('column')
                op = f.get('operator')
                val = f.get('value')

                if not col or not op or val is None:
                    return jsonify({"error": "Invalid filter format"}), 400
                if not isinstance(col, str) or not col.isidentifier():
                    return jsonify({"error": f"Invalid filter column name: {col}"}), 400

                # Basic operator validation
                allowed_operators = ['=', '!=', '<', '>', '<=', '>=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL']
                if op not in allowed_operators:
                    return jsonify({"error": f"Unsupported operator: {op}"}), 400

                if op in ['IS NULL', 'IS NOT NULL']:
                    where_clauses.append(sql.SQL("{} {}").format(sql.Identifier(col), sql.SQL(op)))
                elif op in ['IN', 'NOT IN']:
                    if not isinstance(val, list):
                        return jsonify({"error": f"Value for {op} operator must be a list"}), 400
                    placeholders = sql.SQL(', ').join(sql.Placeholder() * len(val))
                    where_clauses.append(sql.SQL("{} {} ({})").format(sql.Identifier(col), sql.SQL(op), placeholders))
                    params.extend(val)
                else:
                    where_clauses.append(sql.SQL("{} {} {}").format(sql.Identifier(col), sql.SQL(op), sql.Placeholder()))
                    params.append(val)

            if where_clauses:
                query_parts.append(sql.SQL("WHERE {}").format(sql.SQL(" AND ").join(where_clauses)))

        # Build ORDER BY part
        if order_by:
            order_clauses = []
            for ob in order_by:
                col = ob.get('column')
                direction = ob.get('direction', 'ASC').upper()

                if not col:
                    return jsonify({"error": "Order by column is required"}), 400
                if not isinstance(col, str) or not col.isidentifier():
                    return jsonify({"error": f"Invalid order by column name: {col}"}), 400
                if direction not in ['ASC', 'DESC']:
                    return jsonify({"error": f"Invalid order direction: {direction}"}), 400
                order_clauses.append(sql.SQL("{} {}").format(sql.Identifier(col), sql.SQL(direction)))
            query_parts.append(sql.SQL("ORDER BY {}").format(sql.SQL(", ").join(order_clauses)))

        # Build LIMIT and OFFSET part
        if limit is not None:
            if not isinstance(limit, int) or limit < 0:
                return jsonify({"error": "Limit must be a non-negative integer"}), 400
            query_parts.append(sql.SQL("LIMIT {}").format(sql.Placeholder()))
            params.append(limit)

        if offset is not None:
            if not isinstance(offset, int) or offset < 0:
                return jsonify({"error": "Offset must be a non-negative integer"}), 400
            query_parts.append(sql.SQL("OFFSET {}").format(sql.Placeholder()))
            params.append(offset)

        final_query = sql.SQL(" ").join(query_parts)

        cur.execute(final_query, params)
        results = cur.fetchall()
        column_names = [desc[0] for desc in cur.description]

        # Format results into a list of dictionaries
        formatted_results = []
        for row in results:
            formatted_results.append(dict(zip(column_names, row)))

        return jsonify(formatted_results)

    except Error as e:
        print(f"Database error: {e}")
        return jsonify({"error": f"Database query failed: {e}"}), 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500
    finally:
        if conn:
            conn.close()

